{"path": "/tmp/sv-b317ddd82ab5443fa2e215aa0b665a29/Components/ShippingStep.razor", "file_text": "<h3>Shipping Information</h3>

<div class="mb-3">
    <label for="name">Name</label>
    <input id="name" class="form-control" @bind="Shipping.Name" />
</div>

<div class="mb-3">
    <label for="address">Address</label>
    <input id="address" class="form-control" @bind="Shipping.Address" />
</div>

<div class="mb-3">
    <label for="city">City</label>
    <input id="city" class="form-control" @bind="Shipping.City" />
</div>

<div class="mb-3">
    <label for="zip">Zip Code</label>
    <input id="zip" class="form-control" @bind="Shipping.ZipCode" />
</div>

@if (!string.IsNullOrEmpty(validationMessage))
{
    <div class="text-danger mb-3">@validationMessage</div>
}

<button class="btn btn-primary" @onclick="HandleNext">Next</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    private string? validationMessage;

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name) || string.IsNullOrWhiteSpace(Shipping.Address))
        {
            validationMessage = "Name and Address are required.";
            return;
        }

        validationMessage = null;
        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-b317ddd82ab5443fa2e215aa0b665a29/Components/PaymentStep.razor", "file_text": "<h3>Payment Information</h3>

<div class="mb-3">
    <label for="card">Card Number</label>
    <input id="card" class="form-control" @bind="Payment.CardNumber" />
</div>

<div class="mb-3">
    <label for="expiry">Expiry Date</label>
    <input id="expiry" class="form-control" @bind="Payment.ExpiryDate" />
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-success" @onclick="OnPlaceOrder">Place Order</button>
</div>

@code {
    [Parameter, EditorRequired]
    public PaymentInfo Payment { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnPlaceOrder { get; set; }
}
"}

{"path": "/tmp/sv-b317ddd82ab5443fa2e215aa0b665a29/Components/CheckoutWizard.razor", "file_text": "<div class="checkout-wizard">
    @if (step == Step.Shipping)
    {
        <ShippingStep Shipping="order.Shipping" OnNext="GoToPayment" />
    }
    else
    {
        <PaymentStep Payment="order.Payment"
                     OnBack="GoToShipping"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private enum Step { Shipping, Payment }
    private Step step = Step.Shipping;
    private Order order = new();

    private void GoToPayment() => step = Step.Payment;
    private void GoToShipping() => step = Step.Shipping;

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(order);
    }
}
"}

